/* GENERATED by /tmp/dax_writeprog.py — exercise library + default plan. */
export const LIBRARY = {"Dumbbell_Shoulder_Press": {"id": "Dumbbell_Shoulder_Press", "name": "Dumbbell Shoulder Press", "group": "Shoulders", "muscle": "shoulders", "equipment": "dumbbell", "level": "intermediate", "frames": ["/assets/exercises/Dumbbell_Shoulder_Press/0.jpg", "/assets/exercises/Dumbbell_Shoulder_Press/1.jpg"], "cues": ["While holding a dumbbell in each hand, sit on a military press bench or utility bench that has back support. Place the dumbbells upright on top of your thighs.", "Now raise the dumbbells to shoulder height one at a time using your thighs to help propel them up into position.", "Make sure to rotate your wrists so that the palms of your hands are facing forward. This is your starting position.", "Now, exhale and push the dumbbells upward until they touch at the top.", "Then, after a brief pause at the top contracted position, slowly lower the weights back down to the starting position while inhaling.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Pike push-ups, or band overhead press"}, "Incline_Dumbbell_Press": {"id": "Incline_Dumbbell_Press", "name": "Incline Dumbbell Press", "group": "Chest", "muscle": "chest", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Incline_Dumbbell_Press/0.jpg", "/assets/exercises/Incline_Dumbbell_Press/1.jpg"], "cues": ["Lie back on an incline bench with a dumbbell in each hand atop your thighs. The palms of your hands will be facing each other.", "Then, using your thighs to help push the dumbbells up, lift the dumbbells one at a time so that you can hold them at shoulder width.", "Once you have the dumbbells raised to shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.", "Be sure to keep full control of the dumbbells at all times. Then breathe out and push the dumbbells up with your chest.", "Lock your arms at the top, hold for a second, and then start slowly lowering the weight. Tip Ideally, lowering the weights should take about twice as long as raising them.", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, place the dumbbells back on your thighs and then on the floor. This is the safest manner to release the dumbbells."], "type": "weight", "home": "Feet-low incline push-ups"}, "Leg_Press": {"id": "Leg_Press", "name": "Leg Press", "group": "Legs", "muscle": "quadriceps", "equipment": "machine", "level": "beginner", "frames": ["/assets/exercises/Leg_Press/0.jpg", "/assets/exercises/Leg_Press/1.jpg"], "cues": ["Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a medium (shoulder width) foot stance. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).", "Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you. Tip: Make sure that you do not lock your knees. Your torso and the legs should make a perfect 90-degree angle. This will be your starting position.", "As you inhale, slowly lower the platform until your upper and lower legs make a 90-degree angle.", "Pushing mainly with the heels of your feet and using the quadriceps go back to the starting position as you exhale.", "Repeat for the recommended amount of repetitions and ensure to lock the safety pins properly once you are done. You do not want that platform falling on you fully loaded."], "type": "weight", "home": "Bodyweight squats, double the reps"}, "Cable_Seated_Lateral_Raise": {"id": "Cable_Seated_Lateral_Raise", "name": "Cable Seated Lateral Raise", "group": "Shoulders", "muscle": "shoulders", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Seated_Lateral_Raise/0.jpg", "/assets/exercises/Cable_Seated_Lateral_Raise/1.jpg"], "cues": ["Stand in the middle of two low pulleys that are opposite to each other and place a flat bench right behind you (in perpendicular fashion to you; the narrow edge of the bench should be the one behind you). Select the weight to be used on each pulley.", "Now sit at the edge of the flat bench behind you with your feet placed in front of your knees.", "Bend forward while keeping your back flat and rest your torso on the thighs.", "Have someone give you the single handles attached to the pulleys. Grasp the left pulley with the right hand and the right pulley with the left after you select your weight. The pulleys should run under your knees and your arms will be extended with palms facing each other and a slight bend at the elbows. This will be the starting position.", "While keeping the arms stationary, raise the upper arms to the sides until they are parallel to the floor and at shoulder height. Exhale during the execution of this movement and hold the contraction for a second.", "Slowly lower your arms to the starting position as you inhale.", "Repeat for the recommended amount of repetitions. Tip: Maintain upper arms perpendicular to torso and a fixed elbow position (10 degree to 30 degree angle) throughout exercise."], "type": "weight", "home": "Water-bottle or band lateral raises"}, "Triceps_Pushdown": {"id": "Triceps_Pushdown", "name": "Triceps Pushdown", "group": "Triceps", "muscle": "triceps", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Triceps_Pushdown/0.jpg", "/assets/exercises/Triceps_Pushdown/1.jpg"], "cues": ["Attach a straight or angled bar to a high pulley and grab with an overhand grip (palms facing down) at shoulder width.", "Standing upright with the torso straight and a very small inclination forward, bring the upper arms close to your body and perpendicular to the floor. The forearms should be pointing up towards the pulley as they hold the bar. This is your starting position.", "Using the triceps, bring the bar down until it touches the front of your thighs and the arms are fully extended perpendicular to the floor. The upper arms should always remain stationary next to your torso and only the forearms should move. Exhale as you perform this movement.", "After a second hold at the contracted position, bring the bar slowly up to the starting point. Breathe in as you perform this step.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Chair or bench dips"}, "Plank": {"id": "Plank", "name": "Plank", "group": "Core", "muscle": "abdominals", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Plank/0.jpg", "/assets/exercises/Plank/1.jpg"], "cues": ["Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder.", "Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised."], "type": "timed", "home": "Same, anywhere"}, "Close-Grip_Front_Lat_Pulldown": {"id": "Close-Grip_Front_Lat_Pulldown", "name": "Close-Grip Front Lat Pulldown", "group": "Back", "muscle": "lats", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Close-Grip_Front_Lat_Pulldown/0.jpg", "/assets/exercises/Close-Grip_Front_Lat_Pulldown/1.jpg"], "cues": ["Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.", "Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.", "As you have both arms extended in front of you - while holding the bar at the chosen grip width - bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.", "As you breathe out, bring the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary (only the arms should move). The forearms should do no other work except for holding the bar; therefore do not try to pull the bar down using the forearms.", "After a second in the contracted position, while squeezing your shoulder blades together, slowly raise the bar back to the starting position when your arms are fully extended and the lats are fully stretched. Inhale during this portion of the movement.", "6. Repeat this motion for the prescribed amount of repetitions."], "type": "weight", "home": "Band pulldowns or doorway rows"}, "Seated_Cable_Rows": {"id": "Seated_Cable_Rows", "name": "Seated Cable Rows", "group": "Back", "muscle": "middle back", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Seated_Cable_Rows/0.jpg", "/assets/exercises/Seated_Cable_Rows/1.jpg"], "cues": ["For this exercise you will need access to a low pulley row machine with a V-bar. Note: The V-bar will enable you to have a neutral grip where the palms of your hands face each other. To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.", "Lean over as you keep the natural alignment of your back and grab the V-bar handles.", "With your arms extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lats as you hold the bar in front of you. This is the starting position of the exercise.", "Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it until you touch the abdominals. Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard. Hold that contraction for a second and slowly go back to the original position while breathing in.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack bent-over rows"}, "Romanian_Deadlift": {"id": "Romanian_Deadlift", "name": "Romanian Deadlift", "group": "Legs", "muscle": "hamstrings", "equipment": "barbell", "level": "intermediate", "frames": ["/assets/exercises/Romanian_Deadlift/0.jpg", "/assets/exercises/Romanian_Deadlift/1.jpg"], "cues": ["Put a barbell in front of you on the ground and grab it using a pronated (palms facing down) grip that a little wider than shoulder width. Tip: Depending on the weight used, you may need wrist wraps to perform the exercise and also a raised platform in order to allow for better range of motion.", "Bend the knees slightly and keep the shins vertical, hips back and back straight. This will be your starting position.", "Keeping your back and arms completely straight at all times, use your hips to lift the bar as you exhale. Tip: The movement should not be fast but steady and under control.", "Once you are standing completely straight up, lower the bar by pushing the hips back, only slightly bending the knees, unlike when squatting. Tip: Take a deep breath at the start of the movement and keep your chest up. Hold your breath as you lower and exhale as you complete the movement.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Single-leg RDL holding a backpack"}, "Face_Pull": {"id": "Face_Pull", "name": "Face Pull", "group": "Shoulders", "muscle": "shoulders", "equipment": "cable", "level": "intermediate", "frames": ["/assets/exercises/Face_Pull/0.jpg", "/assets/exercises/Face_Pull/1.jpg"], "cues": ["Facing a high pulley with a rope or dual handles attached, pull the weight directly towards your face, separating your hands as you do so. Keep your upper arms parallel to the ground."], "type": "weight", "home": "Band face pulls"}, "Dumbbell_Bicep_Curl": {"id": "Dumbbell_Bicep_Curl", "name": "Dumbbell Bicep Curl", "group": "Biceps", "muscle": "biceps", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Dumbbell_Bicep_Curl/0.jpg", "/assets/exercises/Dumbbell_Bicep_Curl/1.jpg"], "cues": ["Stand up straight with a dumbbell in each hand at arm's length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.", "Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps.", "Then, inhale and slowly begin to lower the dumbbells back to the starting position.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack or band curls"}, "Hanging_Leg_Raise": {"id": "Hanging_Leg_Raise", "name": "Hanging Leg Raise", "group": "Core", "muscle": "abdominals", "equipment": "body only", "level": "expert", "frames": ["/assets/exercises/Hanging_Leg_Raise/0.jpg", "/assets/exercises/Hanging_Leg_Raise/1.jpg"], "cues": ["Hang from a chin-up bar with both arms extended at arms length in top of you using either a wide grip or a medium grip. The legs should be straight down with the pelvis rolled slightly backwards. This will be your starting position.", "Raise your legs until the torso makes a 90-degree angle with the legs. Exhale as you perform this movement and hold the contraction for a second or so.", "Go back slowly to the starting position as you breathe in.", "Repeat for the recommended amount of repetitions."], "type": "bodyweight", "home": "Lying leg raises on the floor"}, "Seated_Leg_Curl": {"id": "Seated_Leg_Curl", "name": "Seated Leg Curl", "group": "Legs", "muscle": "hamstrings", "equipment": "machine", "level": "beginner", "frames": ["/assets/exercises/Seated_Leg_Curl/0.jpg", "/assets/exercises/Seated_Leg_Curl/1.jpg"], "cues": ["Adjust the machine lever to fit your height and sit on the machine with your back against the back support pad.", "Place the back of lower leg on top of padded lever (just a few inches under the calves) and secure the lap pad against your thighs, just above the knees. Then grasp the side handles on the machine as you point your toes straight (or you can also use any of the other two stances) and ensure that the legs are fully straight right in front of you. This will be your starting position.", "As you exhale, pull the machine lever as far as possible to the back of your thighs by flexing at the knees. Keep your torso stationary at all times. Hold the contracted position for a second.", "Slowly return to the starting position as you breathe in.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Nordic curl negatives"}, "Dumbbell_Lunges": {"id": "Dumbbell_Lunges", "name": "Dumbbell Lunges", "group": "Legs", "muscle": "quadriceps", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Dumbbell_Lunges/0.jpg", "/assets/exercises/Dumbbell_Lunges/1.jpg"], "cues": ["Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.", "Step forward with your right leg around 2 feet or so from the foot being left stationary behind and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Note: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground.", "Using mainly the heel of your foot, push up and go back to the starting position as you exhale.", "Repeat the movement for the recommended amount of repetitions and then perform with the left leg."], "type": "weight", "home": "Bodyweight walking lunges"}, "Standing_Calf_Raises": {"id": "Standing_Calf_Raises", "name": "Standing Calf Raises", "group": "Legs", "muscle": "calves", "equipment": "machine", "level": "beginner", "frames": ["/assets/exercises/Standing_Calf_Raises/0.jpg", "/assets/exercises/Standing_Calf_Raises/1.jpg"], "cues": ["Adjust the padded lever of the calf raise machine to fit your height.", "Place your shoulders under the pads provided and position your toes facing forward (or using any of the two other positions described at the beginning of the chapter). The balls of your feet should be secured on top of the calf block with the heels extending off it. Push the lever up by extending your hips and knees until your torso is standing erect. The knees should be kept with a slight bend; never locked. Toes should be facing forward, outwards or inwards as described at the beginning of the chapter. This will be your starting position.", "Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.", "Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Single-leg calf raises off a step"}, "Alternating_Floor_Press": {"id": "Alternating_Floor_Press", "name": "Alternating Floor Press", "group": "Chest", "muscle": "chest", "equipment": "kettlebells", "level": "beginner", "frames": ["/assets/exercises/Alternating_Floor_Press/0.jpg", "/assets/exercises/Alternating_Floor_Press/1.jpg"], "cues": ["Lie on the floor with two kettlebells next to your shoulders.", "Position one in place on your chest and then the other, gripping the kettlebells on the handle with the palms facing forward.", "Extend both arms, so that the kettlebells are being held above your chest. Lower one kettlebell, bringing it to your chest and turn the wrist in the direction of the locked out kettlebell.", "Raise the kettlebell and repeat on the opposite side."], "type": "weight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Barbell_Bench_Press_-_Medium_Grip": {"id": "Barbell_Bench_Press_-_Medium_Grip", "name": "Barbell Bench Press - Medium Grip", "group": "Chest", "muscle": "chest", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Barbell_Bench_Press_-_Medium_Grip/0.jpg", "/assets/exercises/Barbell_Bench_Press_-_Medium_Grip/1.jpg"], "cues": ["Lie back on a flat bench. Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.", "From the starting position, breathe in and begin coming down slowly until the bar touches your middle chest.", "After a brief pause, push the bar back to the starting position as you breathe out. Focus on pushing the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position at the top of the motion, hold for a second and then start coming down slowly again. Tip: Ideally, lowering the weight should take about twice as long as raising it.", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, place the bar back in the rack."], "type": "weight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Barbell_Incline_Bench_Press_-_Medium_Grip": {"id": "Barbell_Incline_Bench_Press_-_Medium_Grip", "name": "Barbell Incline Bench Press - Medium Grip", "group": "Chest", "muscle": "chest", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Barbell_Incline_Bench_Press_-_Medium_Grip/0.jpg", "/assets/exercises/Barbell_Incline_Bench_Press_-_Medium_Grip/1.jpg"], "cues": ["Lie back on an incline bench. Using a medium-width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.", "As you breathe in, come down slowly until you feel the bar on you upper chest.", "After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly again. Tip: it should take at least twice as long to go down than to come up.", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, place the bar back in the rack."], "type": "weight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Bench_Press_-_With_Bands": {"id": "Bench_Press_-_With_Bands", "name": "Bench Press - With Bands", "group": "Chest", "muscle": "chest", "equipment": "bands", "level": "beginner", "frames": ["/assets/exercises/Bench_Press_-_With_Bands/0.jpg", "/assets/exercises/Bench_Press_-_With_Bands/1.jpg"], "cues": ["Using a flat bench secure a band under the leg of the bench that is nearest to your head.", "Once the band is secure, grab it by both handles and lie down on the bench.", "Extend your arms so that you are holding the band handles in front of you at shoulder width.", "Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.", "Bring down the handles slowly until your elbow forms a 90 degree angle. Keep full control at all times.", "As you breathe out, bring the handles up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.", "Repeat the movement for the prescribed amount of repetitions of your training program."], "type": "weight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Cable_Chest_Press": {"id": "Cable_Chest_Press", "name": "Cable Chest Press", "group": "Chest", "muscle": "chest", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Chest_Press/0.jpg", "/assets/exercises/Cable_Chest_Press/1.jpg"], "cues": ["Adjust the weight to an appropriate amount and be seated, grasping the handles. Your upper arms should be about 45 degrees to the body, with your head and chest up. The elbows should be bent to about 90 degrees. This will be your starting position.", "Begin by extending through the elbow, pressing the handles together straight in front of you. Keep your shoulder blades retracted as you execute the movement.", "After pausing at full extension, return to th starting position, keeping tension on the cables.", "You can also execute this movement with your back off the pad, at an incline or decline, or alternate hands."], "type": "weight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Cross_Over_-_With_Bands": {"id": "Cross_Over_-_With_Bands", "name": "Cross Over - With Bands", "group": "Chest", "muscle": "chest", "equipment": "bands", "level": "beginner", "frames": ["/assets/exercises/Cross_Over_-_With_Bands/0.jpg", "/assets/exercises/Cross_Over_-_With_Bands/1.jpg"], "cues": ["Secure an exercise band around a stationary post.", "While facing away from the post, grab the handles on both ends of the band and step forward enough to create tension on the band.", "Raise your arms to the sides, parallel to the floor, perpendicular to your torso (your torso and the arms should resemble the letter \"T\") and with the palms facing forward. Have them extended with a slight bend at the elbows. This will be your starting position.", "While keeping your arms straight, bring them across your chest in a semicircular motion to the front as you exhale and flex your pecs. Hold the contraction for a second.", "Slowly return to the starting position as you inhale.", "Perform for the recommended amount of repetitions."], "type": "weight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Decline_Barbell_Bench_Press": {"id": "Decline_Barbell_Bench_Press", "name": "Decline Barbell Bench Press", "group": "Chest", "muscle": "chest", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Decline_Barbell_Bench_Press/0.jpg", "/assets/exercises/Decline_Barbell_Bench_Press/1.jpg"], "cues": ["Secure your legs at the end of the decline bench and slowly lay down on the bench.", "Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.", "As you breathe in, come down slowly until you feel the bar on your lower chest.", "After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up).", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, place the bar back in the rack."], "type": "weight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Decline_Dumbbell_Bench_Press": {"id": "Decline_Dumbbell_Bench_Press", "name": "Decline Dumbbell Bench Press", "group": "Chest", "muscle": "chest", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Decline_Dumbbell_Bench_Press/0.jpg", "/assets/exercises/Decline_Dumbbell_Bench_Press/1.jpg"], "cues": ["Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.", "Once you are laying down, move the dumbbells in front of you at shoulder width.", "Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.", "Bring down the weights slowly to your side as you breathe out. Keep full control of the dumbbells at all times. Tip: Throughout the motion, the forearms should always be perpendicular to the floor.", "As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up..", "Repeat the movement for the prescribed amount of repetitions of your training program."], "type": "weight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Decline_Dumbbell_Flyes": {"id": "Decline_Dumbbell_Flyes", "name": "Decline Dumbbell Flyes", "group": "Chest", "muscle": "chest", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Decline_Dumbbell_Flyes/0.jpg", "/assets/exercises/Decline_Dumbbell_Flyes/1.jpg"], "cues": ["Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.", "Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.", "With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint.", "Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.", "Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions."], "type": "weight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Decline_Push-Up": {"id": "Decline_Push-Up", "name": "Decline Push-Up", "group": "Chest", "muscle": "chest", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Decline_Push-Up/0.jpg", "/assets/exercises/Decline_Push-Up/1.jpg"], "cues": ["Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length. Move your feet up to a box or bench. This will be your starting position.", "Next, lower yourself downward until your chest almost touches the floor as you inhale.", "Now breathe out and press your upper body back up to the starting position while squeezing your chest.", "After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed."], "type": "bodyweight", "home": "Push-ups, adjust the angle to scale difficulty"}, "Bent_Over_Barbell_Row": {"id": "Bent_Over_Barbell_Row", "name": "Bent Over Barbell Row", "group": "Back", "muscle": "middle back", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Bent_Over_Barbell_Row/0.jpg", "/assets/exercises/Bent_Over_Barbell_Row/1.jpg"], "cues": ["Holding a barbell with a pronated grip (palms facing down), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The barbell should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.", "Now, while keeping the torso stationary, breathe out and lift the barbell to you. Keep the elbows close to the body and only use the forearms to hold the weight. At the top contracted position, squeeze the back muscles and hold for a brief pause.", "Then inhale and slowly lower the barbell back to the starting position.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack rows or sturdy-table inverted rows"}, "Bent_Over_One-Arm_Long_Bar_Row": {"id": "Bent_Over_One-Arm_Long_Bar_Row", "name": "Bent Over One-Arm Long Bar Row", "group": "Back", "muscle": "middle back", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Bent_Over_One-Arm_Long_Bar_Row/0.jpg", "/assets/exercises/Bent_Over_One-Arm_Long_Bar_Row/1.jpg"], "cues": ["Put weight on one of the ends of an Olympic barbell. Make sure that you either place the other end of the barbell in the corner of two walls; or put a heavy object on the ground so the barbell cannot slide backward.", "Bend forward until your torso is as close to parallel with the floor as you can and keep your knees slightly bent.", "Now grab the bar with one arm just behind the plates on the side where the weight was placed and put your other hand on your knee. This will be your starting position.", "Pull the bar straight up with your elbow in (to maximize back stimulation) until the plates touch your lower chest. Squeeze the back muscles as you lift the weight up and hold for a second at the top of the movement. Breathe out as you lift the weight. Tip: Do not allow for any swinging of the torso. Only the arm should move.", "Slowly lower the bar to the starting position getting a nice stretch on the lats. Tip: Do not let the plates touch the floor. To ensure the best range of motion, I recommend using small plates (25-lb ones) as opposed to larger plates (like 35-45lb ones).", "Repeat for the recommended amount of repetitions and switch arms."], "type": "weight", "home": "Backpack rows or sturdy-table inverted rows"}, "Bent_Over_Two-Dumbbell_Row": {"id": "Bent_Over_Two-Dumbbell_Row", "name": "Bent Over Two-Dumbbell Row", "group": "Back", "muscle": "middle back", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Bent_Over_Two-Dumbbell_Row/0.jpg", "/assets/exercises/Bent_Over_Two-Dumbbell_Row/1.jpg"], "cues": ["With a dumbbell in each hand (palms facing your torso), bend your knees slightly and bring your torso forward by bending at the waist; as you bend make sure to keep your back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.", "While keeping the torso stationary, lift the dumbbells to your side (as you breathe out), keeping the elbows close to the body (do not exert any force with the forearm other than holding the weights). On the top contracted position, squeeze the back muscles and hold for a second.", "Slowly lower the weight again to the starting position as you inhale.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack rows or sturdy-table inverted rows"}, "Bent_Over_Two-Dumbbell_Row_With_Palms_In": {"id": "Bent_Over_Two-Dumbbell_Row_With_Palms_In", "name": "Bent Over Two-Dumbbell Row With Palms In", "group": "Back", "muscle": "middle back", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Bent_Over_Two-Dumbbell_Row_With_Palms_In/0.jpg", "/assets/exercises/Bent_Over_Two-Dumbbell_Row_With_Palms_In/1.jpg"], "cues": ["With a dumbbell in each hand (palms facing each other), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.", "While keeping the torso stationary, lift the dumbbells to your side as you breathe out, squeezing your shoulder blades together. On the top contracted position, squeeze the back muscles and hold for a second.", "Slowly lower the weight again to the starting position as you inhale.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack rows or sturdy-table inverted rows"}, "Chin-Up": {"id": "Chin-Up", "name": "Chin-Up", "group": "Back", "muscle": "lats", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Chin-Up/0.jpg", "/assets/exercises/Chin-Up/1.jpg"], "cues": ["Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width.", "As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement.", "As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.", "After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement.", "Repeat this motion for the prescribed amount of repetitions."], "type": "bodyweight", "home": "Backpack rows or sturdy-table inverted rows"}, "Clean_Shrug": {"id": "Clean_Shrug", "name": "Clean Shrug", "group": "Back", "muscle": "traps", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Clean_Shrug/0.jpg", "/assets/exercises/Clean_Shrug/1.jpg"], "cues": ["Begin with a shoulder width, double overhand or hook grip, with the bar hanging at the mid thigh position. Your back should be straight and inclined slightly forward.", "Shrug your shoulders towards your ears. While this exercise can usually by loaded with heavier weight than a clean, avoid overloading to the point that the execution slows down."], "type": "weight", "home": "Backpack rows or sturdy-table inverted rows"}, "Dumbbell_Incline_Row": {"id": "Dumbbell_Incline_Row", "name": "Dumbbell Incline Row", "group": "Back", "muscle": "middle back", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Dumbbell_Incline_Row/0.jpg", "/assets/exercises/Dumbbell_Incline_Row/1.jpg"], "cues": ["Using a neutral grip, lean into an incline bench.", "Take a dumbbell in each hand with a neutral grip, beginning with the arms straight. This will be your starting position.", "Retract the shoulder blades and flex the elbows to row the dumbbells to your side.", "Pause at the top of the motion, and then return to the starting position."], "type": "weight", "home": "Backpack rows or sturdy-table inverted rows"}, "Inverted_Row": {"id": "Inverted_Row", "name": "Inverted Row", "group": "Back", "muscle": "middle back", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Inverted_Row/0.jpg", "/assets/exercises/Inverted_Row/1.jpg"], "cues": ["Position a bar in a rack to about waist height. You can also use a smith machine.", "Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.", "Begin by flexing the elbow, pulling your chest towards the bar. Retract your shoulder blades as you perform the movement.", "Pause at the top of the motion, and return yourself to the start position.", "Repeat for the desired number of repetitions."], "type": "bodyweight", "home": "Backpack rows or sturdy-table inverted rows"}, "Kneeling_High_Pulley_Row": {"id": "Kneeling_High_Pulley_Row", "name": "Kneeling High Pulley Row", "group": "Back", "muscle": "lats", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Kneeling_High_Pulley_Row/0.jpg", "/assets/exercises/Kneeling_High_Pulley_Row/1.jpg"], "cues": ["Select the appropriate weight using a pulley that is above your head. Attach a rope to the cable and kneel a couple of feet away, holding the rope out in front of you with both arms extended. This will be your starting position.", "Initiate the movement by flexing the elbows and fully retracting your shoulders, pulling the rope toward your upper chest with your elbows out.", "After pausing briefly, slowly return to the starting position."], "type": "weight", "home": "Backpack rows or sturdy-table inverted rows"}, "Kneeling_Single-Arm_High_Pulley_Row": {"id": "Kneeling_Single-Arm_High_Pulley_Row", "name": "Kneeling Single-Arm High Pulley Row", "group": "Back", "muscle": "lats", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Kneeling_Single-Arm_High_Pulley_Row/0.jpg", "/assets/exercises/Kneeling_Single-Arm_High_Pulley_Row/1.jpg"], "cues": ["Attach a single handle to a high pulley and make your weight selection.", "Kneel in front of the cable tower, taking the cable with one hand with your arm extended. This will be your starting position.", "Starting with your palm facing forward, pull the weight down to your torso by flexing the elbow and retract the shoulder blade. As you do so, rotate the wrist so that at the completion of the movement, your palm is now facing you.", "After a brief pause, return to the starting position."], "type": "weight", "home": "Backpack rows or sturdy-table inverted rows"}, "Leverage_High_Row": {"id": "Leverage_High_Row", "name": "Leverage High Row", "group": "Back", "muscle": "middle back", "equipment": "machine", "level": "beginner", "frames": ["/assets/exercises/Leverage_High_Row/0.jpg", "/assets/exercises/Leverage_High_Row/1.jpg"], "cues": ["Load an appropriate weight onto the pins and adjust the seat height so that you can just reach the handles above you. Adjust the knee pad to help keep you down. Grasp the handles with a pronated grip. This will be your starting position.", "Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.", "Pause at the bottom of the motion, and then slowly return the handles to the starting position.", "For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked."], "type": "weight", "home": "Backpack rows or sturdy-table inverted rows"}, "Alternating_Cable_Shoulder_Press": {"id": "Alternating_Cable_Shoulder_Press", "name": "Alternating Cable Shoulder Press", "group": "Shoulders", "muscle": "shoulders", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Alternating_Cable_Shoulder_Press/0.jpg", "/assets/exercises/Alternating_Cable_Shoulder_Press/1.jpg"], "cues": ["Move the cables to the bottom of the tower and select an appropriate weight.", "Grasp the cables and hold them at shoulder height, palms facing forward. This will be your starting position.", "Keeping your head and chest up, extend through the elbow to press one side directly over head.", "After pausing at the top, return to the starting position and repeat on the opposite side."], "type": "weight", "home": "Pike push-ups or band raises"}, "Anti-Gravity_Press": {"id": "Anti-Gravity_Press", "name": "Anti-Gravity Press", "group": "Shoulders", "muscle": "shoulders", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Anti-Gravity_Press/0.jpg", "/assets/exercises/Anti-Gravity_Press/1.jpg"], "cues": ["Place a bar on the ground behind the head of an incline bench.", "Lay on the bench face down. With a pronated grip, pick the barbell up from the floor. Flex the elbows, performing a reverse curl to bring the bar near your chest. This will be your starting position.", "To begin, press the barbell out in front of your head by extending your elbows. Keep your arms parallel to the ground throughout the movement.", "Return to the starting position and repeat to complete the set."], "type": "weight", "home": "Pike push-ups or band raises"}, "Back_Flyes_-_With_Bands": {"id": "Back_Flyes_-_With_Bands", "name": "Back Flyes - With Bands", "group": "Shoulders", "muscle": "shoulders", "equipment": "bands", "level": "beginner", "frames": ["/assets/exercises/Back_Flyes_-_With_Bands/0.jpg", "/assets/exercises/Back_Flyes_-_With_Bands/1.jpg"], "cues": ["Run a band around a stationary post like that of a squat rack.", "Grab the band by the handles and stand back so that the tension in the band rises.", "Extend and lift the arms straight in front of you. Tip: Your arms should be straight and parallel to the floor while perpendicular to your torso. Your feet should be firmly planted on the floor spread at shoulder width. This will be your starting position.", "As you exhale, move your arms to the sides and back. Keep your arms extended and parallel to the floor. Continue the movement until the arms are extended to your sides.", "After a pause, go back to the original position as you inhale.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Pike push-ups or band raises"}, "Barbell_Incline_Shoulder_Raise": {"id": "Barbell_Incline_Shoulder_Raise", "name": "Barbell Incline Shoulder Raise", "group": "Shoulders", "muscle": "shoulders", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Barbell_Incline_Shoulder_Raise/0.jpg", "/assets/exercises/Barbell_Incline_Shoulder_Raise/1.jpg"], "cues": ["Lie back on an Incline Bench. Using a medium width grip (a grip that is slightly wider than shoulder width), lift the bar from the rack and hold it straight over you with your arms straight. This will be your starting position.", "While keeping the arms straight, lift the bar by protracting your shoulder blades, raising the shoulders from the bench as you breathe out.", "Bring back the bar to the starting position as you breathe in.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Pike push-ups or band raises"}, "Barbell_Rear_Delt_Row": {"id": "Barbell_Rear_Delt_Row", "name": "Barbell Rear Delt Row", "group": "Shoulders", "muscle": "shoulders", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Barbell_Rear_Delt_Row/0.jpg", "/assets/exercises/Barbell_Rear_Delt_Row/1.jpg"], "cues": ["Stand up straight while holding a barbell using a wide (higher than shoulder width) and overhand (palms facing your body) grip.", "Bend knees slightly and bend over as you keep the natural arch of your back. Let the arms hang in front of you as they hold the bar. Once your torso is parallel to the floor, flare the elbows out and away from your body. Tip: Your torso and your arms should resemble the letter \"T\". Now you are ready to begin the exercise.", "While keeping the upper arms perpendicular to the torso, pull the barbell up towards your upper chest as you squeeze the rear delts and you breathe out. Tip: When performed correctly, this exercise should resemble a bench press in reverse. Also, refrain from using your biceps to do the work. Focus on targeting the rear delts; the arms should only act as hooks.", "Slowly go back to the initial position as you breathe in.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Pike push-ups or band raises"}, "Bradford_Rocky_Presses": {"id": "Bradford_Rocky_Presses", "name": "Bradford/Rocky Presses", "group": "Shoulders", "muscle": "shoulders", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Bradford_Rocky_Presses/0.jpg", "/assets/exercises/Bradford_Rocky_Presses/1.jpg"], "cues": ["Sit on a Military Press Bench with a bar at shoulder level with a pronated grip (palms facing forward). Tip: Your grip should be wider than shoulder width and it should create a 90-degree angle between the forearm and the upper arm as the barbell goes down. This is your starting position.", "Once you pick up the barbell with the correct grip, lift the bar up over your head by locking your arms.", "Now lower the bar down to the back of the head slowly as you inhale.", "Lift the bar back up to the starting position as you exhale.", "Lower the bar down to the starting position slowly as you inhale. This is one repetition.", "Alternate in this manner until you complete the recommended amount of repetitions."], "type": "weight", "home": "Pike push-ups or band raises"}, "Cable_Internal_Rotation": {"id": "Cable_Internal_Rotation", "name": "Cable Internal Rotation", "group": "Shoulders", "muscle": "shoulders", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Internal_Rotation/0.jpg", "/assets/exercises/Cable_Internal_Rotation/1.jpg"], "cues": ["Sit next to a low pulley sideways (with legs stretched in front of you or crossed) and grasp the single hand cable attachment with the arm nearest to the cable. Tip: If you can adjust the pulley's height, you can use a flat bench to sit on instead.", "Position the elbow against your side with the elbow bent at 90° and the arm pointing towards the pulley. This will be your starting position.", "Pull the single hand cable attachment toward your body by internally rotating your shoulder until your forearm is across your abs. You will be creating an imaginary semi-circle. Tip: The forearm should be perpendicular to your torso at all times.", "Slowly go back to the initial position.", "Repeat for the recommended amount of repetitions and then repeat the movement with the next arm."], "type": "weight", "home": "Pike push-ups or band raises"}, "Cable_Rope_Rear-Delt_Rows": {"id": "Cable_Rope_Rear-Delt_Rows", "name": "Cable Rope Rear-Delt Rows", "group": "Shoulders", "muscle": "shoulders", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Rope_Rear-Delt_Rows/0.jpg", "/assets/exercises/Cable_Rope_Rear-Delt_Rows/1.jpg"], "cues": ["Sit in the same position on a low pulley row station as you would if you were doing seated cable rows for the back.", "Attach a rope to the pulley and grasp it with an overhand grip. Your arms should be extended and parallel to the floor with the elbows flared out.", "Keep your lower back upright and slide your hips back so that your knees are slightly bent. This will be your starting position.", "Pull the cable attachment towards your upper chest, just below the neck, as you keep your elbows up and out to the sides. Continue this motion as you exhale until the elbows travel slightly behind the back. Tip: Keep your upper arms horizontal, perpendicular to the torso and parallel to the floor throughout the motion.", "Go back to the initial position where the arms are extended and the shoulders are stretched forward. Inhale as you perform this portion of the movement.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Pike push-ups or band raises"}, "Alternate_Hammer_Curl": {"id": "Alternate_Hammer_Curl", "name": "Alternate Hammer Curl", "group": "Biceps", "muscle": "biceps", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Alternate_Hammer_Curl/0.jpg", "/assets/exercises/Alternate_Hammer_Curl/1.jpg"], "cues": ["Stand up with your torso upright and a dumbbell in each hand being held at arms length. The elbows should be close to the torso.", "The palms of the hands should be facing your torso. This will be your starting position.", "While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.", "Slowly begin to bring the dumbbells back to starting position as your breathe in.", "Repeat the movement with the left hand. This equals one repetition.", "Continue alternating in this manner for the recommended amount of repetitions."], "type": "weight", "home": "Backpack or resistance-band curls"}, "Alternate_Incline_Dumbbell_Curl": {"id": "Alternate_Incline_Dumbbell_Curl", "name": "Alternate Incline Dumbbell Curl", "group": "Biceps", "muscle": "biceps", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Alternate_Incline_Dumbbell_Curl/0.jpg", "/assets/exercises/Alternate_Incline_Dumbbell_Curl/1.jpg"], "cues": ["Sit down on an incline bench with a dumbbell in each hand being held at arms length. Tip: Keep the elbows close to the torso.This will be your starting position.", "While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. As you do so, rotate the hand so that the palm is facing up. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.", "Slowly begin to bring the dumbbell back to starting position as your breathe in.", "Repeat the movement with the left hand. This equals one repetition.", "Continue alternating in this manner for the recommended amount of repetitions."], "type": "weight", "home": "Backpack or resistance-band curls"}, "Barbell_Curl": {"id": "Barbell_Curl", "name": "Barbell Curl", "group": "Biceps", "muscle": "biceps", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Barbell_Curl/0.jpg", "/assets/exercises/Barbell_Curl/1.jpg"], "cues": ["Stand up with your torso upright while holding a barbell at a shoulder-width grip. The palm of your hands should be facing forward and the elbows should be close to the torso. This will be your starting position.", "While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Tip: Only the forearms should move.", "Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second and squeeze the biceps hard.", "Slowly begin to bring the bar back to starting position as your breathe in.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack or resistance-band curls"}, "Barbell_Curls_Lying_Against_An_Incline": {"id": "Barbell_Curls_Lying_Against_An_Incline", "name": "Barbell Curls Lying Against An Incline", "group": "Biceps", "muscle": "biceps", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Barbell_Curls_Lying_Against_An_Incline/0.jpg", "/assets/exercises/Barbell_Curls_Lying_Against_An_Incline/1.jpg"], "cues": ["Lie against an incline bench, with your arms holding a barbell and hanging down in a horizontal line. This will be your starting position.", "While keeping the upper arms stationary, curl the weight up as high as you can while squeezing the biceps. Breathe out as you perform this portion of the movement. Tip: Only the forearms should move. Do not swing the arms.", "After a second contraction, slowly go back to the starting position as you inhale. Tip: Make sure that you go all of the way down.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack or resistance-band curls"}, "Cable_Hammer_Curls_-_Rope_Attachment": {"id": "Cable_Hammer_Curls_-_Rope_Attachment", "name": "Cable Hammer Curls - Rope Attachment", "group": "Biceps", "muscle": "biceps", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Hammer_Curls_-_Rope_Attachment/0.jpg", "/assets/exercises/Cable_Hammer_Curls_-_Rope_Attachment/1.jpg"], "cues": ["Attach a rope attachment to a low pulley and stand facing the machine about 12 inches away from it.", "Grasp the rope with a neutral (palms-in) grip and stand straight up keeping the natural arch of the back and your torso stationary.", "Put your elbows in by your side and keep them there stationary during the entire movement. Tip: Only the forearms should move; not your upper arms. This will be your starting position.", "Using your biceps, pull your arms up as you exhale until your biceps touch your forearms. Tip: Remember to keep the elbows in and your upper arms stationary.", "After a 1 second contraction where you squeeze your biceps, slowly start to bring the weight back to the original position.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack or resistance-band curls"}, "Cable_Preacher_Curl": {"id": "Cable_Preacher_Curl", "name": "Cable Preacher Curl", "group": "Biceps", "muscle": "biceps", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Preacher_Curl/0.jpg", "/assets/exercises/Cable_Preacher_Curl/1.jpg"], "cues": ["Place a preacher bench about 2 feet in front of a pulley machine.", "Attach a straight bar to the low pulley.", "Sit at the preacher bench with your elbow and upper arms firmly on top of the bench pad and have someone hand you the bar from the low pulley.", "Grab the bar and fully extend your arms on top of the preacher bench pad. This will be your starting position.", "Now start pilling the weight up towards your shoulders and squeeze the biceps hard at the top of the movement. Exhale as you perform this motion. Also, hold for a second at the top.", "Now slowly lower the weight to the starting position.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack or resistance-band curls"}, "Cable_Wrist_Curl": {"id": "Cable_Wrist_Curl", "name": "Cable Wrist Curl", "group": "Biceps", "muscle": "forearms", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Wrist_Curl/0.jpg", "/assets/exercises/Cable_Wrist_Curl/1.jpg"], "cues": ["Start out by placing a flat bench in front of a low pulley cable that has a straight bar attachment.", "Use your arms to grab the cable bar with a narrow to shoulder width supinated grip (palms up) and bring them up so that your forearms are resting against the top of your thighs. Your wrists should be hanging just beyond your knees.", "Start out by curling your wrist upwards and exhaling. Keep the contraction for a second.", "Slowly lower your wrists back down to the starting position while inhaling.", "Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Backpack or resistance-band curls"}, "Bench_Dips": {"id": "Bench_Dips", "name": "Bench Dips", "group": "Triceps", "muscle": "triceps", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Bench_Dips/0.jpg", "/assets/exercises/Bench_Dips/1.jpg"], "cues": ["For this exercise you will need to place a bench behind your back. With the bench perpendicular to your body, and while looking away from it, hold on to the bench on its edge with the hands fully extended, separated at shoulder width. The legs will be extended forward, bent at the waist and perpendicular to your torso. This will be your starting position.", "Slowly lower your body as you inhale by bending at the elbows until you lower yourself far enough to where there is an angle slightly smaller than 90 degrees between the upper arm and the forearm. Tip: Keep the elbows as close as possible throughout the movement. Forearms should always be pointing down.", "Using your triceps to bring your torso up again, lift yourself back to the starting position.", "Repeat for the recommended amount of repetitions."], "type": "bodyweight", "home": "Chair / bench dips"}, "Close-Grip_Barbell_Bench_Press": {"id": "Close-Grip_Barbell_Bench_Press", "name": "Close-Grip Barbell Bench Press", "group": "Triceps", "muscle": "triceps", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Close-Grip_Barbell_Bench_Press/0.jpg", "/assets/exercises/Close-Grip_Barbell_Bench_Press/1.jpg"], "cues": ["Lie back on a flat bench. Using a close grip (around shoulder width), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.", "As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that - as opposed to a regular bench press - you keep the elbows close to the torso at all times in order to maximize triceps involvement.", "After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, place the bar back in the rack."], "type": "weight", "home": "Chair / bench dips"}, "Close-Grip_Dumbbell_Press": {"id": "Close-Grip_Dumbbell_Press", "name": "Close-Grip Dumbbell Press", "group": "Triceps", "muscle": "triceps", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Close-Grip_Dumbbell_Press/0.jpg", "/assets/exercises/Close-Grip_Dumbbell_Press/1.jpg"], "cues": ["Place a dumbbell standing up on a flat bench.", "Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench with only your shoulders lying on the surface. Hips should be below the bench and your legs bent with your feet firmly on the floor.", "Grasp the dumbbell with both hands and hold it straight over your chest at arm's length. Both palms should be pressing against the underside of the sides of the dumbbell. This will be your starting position.", "Initiate the movement by lowering the dumbbell to your chest.", "Return to the starting position by extending the elbows."], "type": "weight", "home": "Chair / bench dips"}, "Close-Grip_EZ-Bar_Press": {"id": "Close-Grip_EZ-Bar_Press", "name": "Close-Grip EZ-Bar Press", "group": "Triceps", "muscle": "triceps", "equipment": "e-z curl bar", "level": "beginner", "frames": ["/assets/exercises/Close-Grip_EZ-Bar_Press/0.jpg", "/assets/exercises/Close-Grip_EZ-Bar_Press/1.jpg"], "cues": ["Lie on a flat bench with an EZ bar loaded to an appropriate weight.", "Using a narrow grip lift the bar and hold it straight over your torso with your elbows in. The arms should be perpendicular to the floor. This will be your starting position.", "Now lower the bar down to your lower chest as you breathe in. Keep the elbows in as you perform this movement.", "Using the triceps to push the bar back up, press it back to the starting position by extending the elbows as you exhale.", "Repeat."], "type": "weight", "home": "Chair / bench dips"}, "Dip_Machine": {"id": "Dip_Machine", "name": "Dip Machine", "group": "Triceps", "muscle": "triceps", "equipment": "machine", "level": "beginner", "frames": ["/assets/exercises/Dip_Machine/0.jpg", "/assets/exercises/Dip_Machine/1.jpg"], "cues": ["Sit securely in a dip machine, select the weight and firmly grasp the handles.", "Now keep your elbows in at your sides in order to place emphasis on the triceps. The elbows should be bent at a 90 degree angle.", "As you contract the triceps, extend your arms downwards as you exhale. Tip: At the bottom of the movement, focus on keeping a little bend in your arms to keep tension on the triceps muscle.", "Now slowly let your arms come back up to the starting position as you inhale.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Chair / bench dips"}, "Dips_-_Triceps_Version": {"id": "Dips_-_Triceps_Version", "name": "Dips - Triceps Version", "group": "Triceps", "muscle": "triceps", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Dips_-_Triceps_Version/0.jpg", "/assets/exercises/Dips_-_Triceps_Version/1.jpg"], "cues": ["To get into the starting position, hold your body at arm's length with your arms nearly locked above the bars.", "Now, inhale and slowly lower yourself downward. Your torso should remain upright and your elbows should stay close to your body. This helps to better focus on tricep involvement. Lower yourself until there is a 90 degree angle formed between the upper arm and forearm.", "Then, exhale and push your torso back up using your triceps to bring your body back to the starting position.", "Repeat the movement for the prescribed amount of repetitions."], "type": "bodyweight", "home": "Chair / bench dips"}, "Incline_Push-Up_Close-Grip": {"id": "Incline_Push-Up_Close-Grip", "name": "Incline Push-Up Close-Grip", "group": "Triceps", "muscle": "triceps", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Incline_Push-Up_Close-Grip/0.jpg", "/assets/exercises/Incline_Push-Up_Close-Grip/1.jpg"], "cues": ["Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.", "Place your hands next to one another on the bar.", "Position your feet back from the bar with arms and body straight. This will be your starting position.", "Keeping your body straight, lower your chest to the bar by bending the arms.", "Return to the starting position by extending the elbows, pressing yourself back up."], "type": "bodyweight", "home": "Chair / bench dips"}, "Alternate_Leg_Diagonal_Bound": {"id": "Alternate_Leg_Diagonal_Bound", "name": "Alternate Leg Diagonal Bound", "group": "Legs", "muscle": "quadriceps", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Alternate_Leg_Diagonal_Bound/0.jpg", "/assets/exercises/Alternate_Leg_Diagonal_Bound/1.jpg"], "cues": ["Assume a comfortable stance with one foot slightly in front of the other.", "Begin by pushing off with the front leg, driving the opposite knee forward and as high as possible before landing. Attempt to cover as much distance to each side with each bound.", "It may help to use a line on the ground to guage distance from side to side.", "Repeat the sequence with the other leg."], "type": "bodyweight", "home": "Bodyweight squats and lunges, higher reps"}, "Band_Good_Morning": {"id": "Band_Good_Morning", "name": "Band Good Morning", "group": "Legs", "muscle": "hamstrings", "equipment": "bands", "level": "beginner", "frames": ["/assets/exercises/Band_Good_Morning/0.jpg", "/assets/exercises/Band_Good_Morning/1.jpg"], "cues": ["Using a 41 inch band, stand on one end, spreading your feet a small amount. Bend at the hips to loop the end of the band behind your neck. This will be your starting position.", "Keeping your legs straight, extend through the hips to come to a near vertical position.", "Ensure that you do not round your back as you go down back to the starting position."], "type": "weight", "home": "Bodyweight squats and lunges, higher reps"}, "Band_Good_Morning_Pull_Through": {"id": "Band_Good_Morning_Pull_Through", "name": "Band Good Morning (Pull Through)", "group": "Legs", "muscle": "hamstrings", "equipment": "bands", "level": "beginner", "frames": ["/assets/exercises/Band_Good_Morning_Pull_Through/0.jpg", "/assets/exercises/Band_Good_Morning_Pull_Through/1.jpg"], "cues": ["Loop the band around a post. Standing a little ways away, loop the opposite end around the neck. Your hands can help hold the band in position.", "Begin by bending at the hips, getting your butt back as far as possible. Keep your back flat and bend forward to about 90 degrees. Your knees should be only slightly bent.", "Return to the starting position be driving through with the hips to come back to a standing position."], "type": "weight", "home": "Bodyweight squats and lunges, higher reps"}, "Barbell_Side_Split_Squat": {"id": "Barbell_Side_Split_Squat", "name": "Barbell Side Split Squat", "group": "Legs", "muscle": "quadriceps", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Barbell_Side_Split_Squat/0.jpg", "/assets/exercises/Barbell_Side_Split_Squat/1.jpg"], "cues": ["Stand up straight while holding a barbell placed on the back of your shoulders (slightly below the neck). Your feet should be placed wide apart with the foot of the lead leg angled out to the side. This will be your starting position.", "Lower your body towards the side of your angled foot by bending the knee and hip of your lead leg and while keeping the opposite leg only slightly bent. Breathe in as you lower your body.", "Return to the starting position by extending the hip and knee of the lead leg. Breathe out as you perform this movement.", "After performing the recommended amount of reps, repeat the movement with the opposite leg."], "type": "weight", "home": "Bodyweight squats and lunges, higher reps"}, "Barbell_Squat": {"id": "Barbell_Squat", "name": "Barbell Squat", "group": "Legs", "muscle": "quadriceps", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Barbell_Squat/0.jpg", "/assets/exercises/Barbell_Squat/1.jpg"], "cues": ["This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack to just below shoulder level. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.", "Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.", "Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section).", "Begin to slowly lower the bar by bending the knees and hips as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.", "Begin to raise the bar as you exhale by pushing the floor with the heel of your foot as you straighten the legs again and go back to the starting position.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Bodyweight squats and lunges, higher reps"}, "Barbell_Walking_Lunge": {"id": "Barbell_Walking_Lunge", "name": "Barbell Walking Lunge", "group": "Legs", "muscle": "quadriceps", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Barbell_Walking_Lunge/0.jpg", "/assets/exercises/Barbell_Walking_Lunge/1.jpg"], "cues": ["Begin standing with your feet shoulder width apart and a barbell across your upper back.", "Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot.", "Drive through the heel of your lead foot and extend both knees to raise yourself back up.", "Step forward with your rear foot, repeating the lunge on the opposite leg."], "type": "weight", "home": "Bodyweight squats and lunges, higher reps"}, "Bodyweight_Squat": {"id": "Bodyweight_Squat", "name": "Bodyweight Squat", "group": "Legs", "muscle": "quadriceps", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Bodyweight_Squat/0.jpg", "/assets/exercises/Bodyweight_Squat/1.jpg"], "cues": ["Stand with your feet shoulder width apart. You can place your hands behind your head. This will be your starting position.", "Begin the movement by flexing your knees and hips, sitting back with your hips.", "Continue down to full depth if you are able,and quickly reverse the motion until you return to the starting position. As you squat, keep your head and chest up and push your knees out."], "type": "bodyweight", "home": "Bodyweight squats and lunges, higher reps"}, "Bodyweight_Walking_Lunge": {"id": "Bodyweight_Walking_Lunge", "name": "Bodyweight Walking Lunge", "group": "Legs", "muscle": "quadriceps", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Bodyweight_Walking_Lunge/0.jpg", "/assets/exercises/Bodyweight_Walking_Lunge/1.jpg"], "cues": ["Begin standing with your feet shoulder width apart and your hands on your hips.", "Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot.", "Drive through the heel of your lead foot and extend both knees to raise yourself back up.", "Step forward with your rear foot, repeating the lunge on the opposite leg."], "type": "bodyweight", "home": "Bodyweight squats and lunges, higher reps"}, "Cable_Deadlifts": {"id": "Cable_Deadlifts", "name": "Cable Deadlifts", "group": "Legs", "muscle": "quadriceps", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Deadlifts/0.jpg", "/assets/exercises/Cable_Deadlifts/1.jpg"], "cues": ["Move the cables to the bottom of the towers and select an appropriate weight. Stand directly in between the uprights.", "To begin, squat down be flexing your hips and knees until you can reach the handles.", "After grasping them, begin your ascent. Driving through your heels extend your hips and knees keeping your hands hanging at your side. Keep your head and chest up throughout the movement.", "After reaching a full standing position, Return to the starting position and repeat."], "type": "weight", "home": "Bodyweight squats and lunges, higher reps"}, "Chair_Squat": {"id": "Chair_Squat", "name": "Chair Squat", "group": "Legs", "muscle": "quadriceps", "equipment": "machine", "level": "beginner", "frames": ["/assets/exercises/Chair_Squat/0.jpg", "/assets/exercises/Chair_Squat/1.jpg"], "cues": ["To begin, first set the bar to a position that best matches your height. Once the bar is loaded, step under it and position it across the back of your shoulders.", "Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs.", "Move your feet forward about 18 inches in front of the bar. Position your legs using a shoulder width stance with the toes slightly pointed out. Look forward at all times and maintain a neutral or slightly arched spine. This will be your starting position.", "Slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper and lower leg breaks 90 degrees.", "Begin to raise the bar as you exhale by pushing the floor with the heels of your feet, extending the knees and returning to the starting position.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Bodyweight squats and lunges, higher reps"}, "Clean_Deadlift": {"id": "Clean_Deadlift", "name": "Clean Deadlift", "group": "Legs", "muscle": "hamstrings", "equipment": "barbell", "level": "beginner", "frames": ["/assets/exercises/Clean_Deadlift/0.jpg", "/assets/exercises/Clean_Deadlift/1.jpg"], "cues": ["Begin standing with a barbell close to your shins. Your feet should be directly under your hips with your feet turned out slightly. Grip the bar with a double overhand grip or hook grip, about shoulder width apart. Squat down to the bar. Your spine should be in full extension, with a back angle that places your shoulders in front of the bar and your back as vertical as possible.", "Begin by driving through the floor through the front of your heels. As the bar travels upward, maintain a constant back angle. Flare your knees out to the side to help keep them out of the bar's path.", "After the bar crosses the knees, complete the lift by driving the hips into the bar until your hips and knees are extended."], "type": "weight", "home": "Bodyweight squats and lunges, higher reps"}, "3_4_Sit-Up": {"id": "3_4_Sit-Up", "name": "3/4 Sit-Up", "group": "Core", "muscle": "abdominals", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/3_4_Sit-Up/0.jpg", "/assets/exercises/3_4_Sit-Up/1.jpg"], "cues": ["Lie down on the floor and secure your feet. Your legs should be bent at the knees.", "Place your hands behind or to the side of your head. You will begin with your back on the ground. This will be your starting position.", "Flex your hips and spine to raise your torso toward your knees.", "At the top of the contraction your torso should be perpendicular to the ground. Reverse the motion, going only ¾ of the way down.", "Repeat for the recommended amount of repetitions."], "type": "bodyweight", "home": "Floor leg raises and planks"}, "Air_Bike": {"id": "Air_Bike", "name": "Air Bike", "group": "Core", "muscle": "abdominals", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Air_Bike/0.jpg", "/assets/exercises/Air_Bike/1.jpg"], "cues": ["Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put your hands beside your head. Be careful however to not strain with the neck as you perform it. Now lift your shoulders into the crunch position.", "Bring knees up to where they are perpendicular to the floor, with your lower legs parallel to the floor. This will be your starting position.", "Now simultaneously, slowly go through a cycle pedal motion kicking forward with the right leg and bringing in the knee of the left leg. Bring your right elbow close to your left knee by crunching to the side, as you breathe out.", "Go back to the initial position as you breathe in.", "Crunch to the opposite side as you cycle your legs and bring closer your left elbow to your right knee and exhale.", "Continue alternating in this manner until all of the recommended repetitions for each side have been completed."], "type": "bodyweight", "home": "Floor leg raises and planks"}, "Bent-Knee_Hip_Raise": {"id": "Bent-Knee_Hip_Raise", "name": "Bent-Knee Hip Raise", "group": "Core", "muscle": "abdominals", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Bent-Knee_Hip_Raise/0.jpg", "/assets/exercises/Bent-Knee_Hip_Raise/1.jpg"], "cues": ["Lay flat on the floor with your arms next to your sides.", "Now bend your knees at around a 75 degree angle and lift your feet off the floor by around 2 inches.", "Using your lower abs, bring your knees in towards you as you maintain the 75 degree angle bend in your legs. Continue this movement until you raise your hips off of the floor by rolling your pelvis backward. Breathe out as you perform this portion of the movement. Tip: At the end of the movement your knees will be over your chest.", "Squeeze your abs at the top of the movement for a second and then return to the starting position slowly as you breathe in. Tip: Maintain a controlled motion at all times.", "Repeat for the recommended amount of repetitions."], "type": "bodyweight", "home": "Floor leg raises and planks"}, "Bottoms_Up": {"id": "Bottoms_Up", "name": "Bottoms Up", "group": "Core", "muscle": "abdominals", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Bottoms_Up/0.jpg", "/assets/exercises/Bottoms_Up/1.jpg"], "cues": ["Begin by lying on your back on the ground. Your legs should be straight and your arms at your side. This will be your starting position.", "To perform the movement, tuck the knees toward your chest by flexing the hips and knees. Following this, extend your legs directly above you so that they are perpendicular to the ground. Rotate and elevate your pelvis to raise your glutes from the floor.", "After a brief pause, return to the starting position."], "type": "bodyweight", "home": "Floor leg raises and planks"}, "Butt-Ups": {"id": "Butt-Ups", "name": "Butt-Ups", "group": "Core", "muscle": "abdominals", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Butt-Ups/0.jpg", "/assets/exercises/Butt-Ups/1.jpg"], "cues": ["Begin a pushup position but with your elbows on the ground and resting on your forearms. Your arms should be bent at a 90 degree angle.", "Arch your back slightly out rather than keeping your back completely straight.", "Raise your glutes toward the ceiling, squeezing your abs tightly to close the distance between your ribcage and hips. The end result will be that you'll end up in a high bridge position. Exhale as you perform this portion of the movement.", "Lower back down slowly to your starting position as you breathe in. Tip: Don't let your back sag downwards.", "Repeat for the recommended amount of repetitions."], "type": "bodyweight", "home": "Floor leg raises and planks"}, "Cable_Judo_Flip": {"id": "Cable_Judo_Flip", "name": "Cable Judo Flip", "group": "Core", "muscle": "abdominals", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Judo_Flip/0.jpg", "/assets/exercises/Cable_Judo_Flip/1.jpg"], "cues": ["Connect a rope attachment to a tower, and move the cable to the lowest pulley position. Stand with your side to the cable with a wide stance, and grab the rope with both hands.", "Twist your body away from the pulley as you bring the rope over your shoulder like you're performing a judo flip.", "Shift your weight between your feet as you twist and crunch forward, pulling the cable downward.", "Return to the starting position and repeat until failure.", "Then, reposition and repeat the same series of movements on the opposite side."], "type": "weight", "home": "Floor leg raises and planks"}, "Side_Lateral_Raise": {"id": "Side_Lateral_Raise", "name": "Side Lateral Raise", "group": "Shoulders", "muscle": "shoulders", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Side_Lateral_Raise/0.jpg", "/assets/exercises/Side_Lateral_Raise/1.jpg"], "cues": ["Pick a couple of dumbbells and stand with a straight torso and the dumbbells by your side at arms length with the palms of the hand facing you. This will be your starting position.", "While maintaining the torso in a stationary position (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.", "Lower the dumbbells back down slowly to the starting position as you inhale.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Lateral raises with any weight or a resistance band out to the sides"}, "Wide-Grip_Lat_Pulldown": {"id": "Wide-Grip_Lat_Pulldown", "name": "Wide-Grip Lat Pulldown", "group": "Back", "muscle": "lats", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Wide-Grip_Lat_Pulldown/0.jpg", "/assets/exercises/Wide-Grip_Lat_Pulldown/1.jpg"], "cues": ["Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.", "Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.", "As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.", "As you breathe out, bring the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the bar; therefore do not try to pull down the bar using the forearms.", "After a second at the contracted position squeezing your shoulder blades together, slowly raise the bar back to the starting position when your arms are fully extended and the lats are fully stretched. Inhale during this portion of the movement.", "Repeat this motion for the prescribed amount of repetitions."], "type": "weight", "home": "Pull-ups, or band lat pulldowns"}, "Cable_Rope_Overhead_Triceps_Extension": {"id": "Cable_Rope_Overhead_Triceps_Extension", "name": "Cable Rope Overhead Triceps Extension", "group": "Triceps", "muscle": "triceps", "equipment": "cable", "level": "beginner", "frames": ["/assets/exercises/Cable_Rope_Overhead_Triceps_Extension/0.jpg", "/assets/exercises/Cable_Rope_Overhead_Triceps_Extension/1.jpg"], "cues": ["Attach a rope to the bottom pulley of the pulley machine.", "Grasping the rope with both hands, extend your arms with your hands directly above your head using a neutral grip (palms facing each other). Your elbows should be in close to your head and the arms should be perpendicular to the floor with the knuckles aimed at the ceiling. This will be your starting position.", "Slowly lower the rope behind your head as you hold the upper arms stationary. Inhale as you perform this movement and pause when your triceps are fully stretched.", "Return to the starting position by flexing your triceps as you breathe out.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Overhead dumbbell or band triceps extension"}, "Incline_Dumbbell_Curl": {"id": "Incline_Dumbbell_Curl", "name": "Incline Dumbbell Curl", "group": "Biceps", "muscle": "biceps", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Incline_Dumbbell_Curl/0.jpg", "/assets/exercises/Incline_Dumbbell_Curl/1.jpg"], "cues": ["Sit back on an incline bench with a dumbbell in each hand held at arms length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.", "While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second.", "Slowly begin to bring the dumbbells back to starting position as your breathe in.", "Repeat for the recommended amount of repetitions."], "type": "weight", "home": "Seated incline curls, or band curls"}, "Dead_Hang": {"id": "Dead_Hang", "name": "Dead Hang", "group": "Forearms", "muscle": "forearms", "equipment": "body only", "level": "beginner", "frames": ["/assets/exercises/Dead_Hang/0.jpg"], "cues": ["Set up under a pull-up bar and take an overhand grip a little wider than your shoulders.", "Step or jump off and let your body hang straight, arms fully extended.", "Keep your shoulders slightly engaged rather than fully slack, ribs down, legs still.", "Hold for as long as you can, then step down under control."], "type": "timed", "home": "Hang from a sturdy door frame pull-up bar or a tree branch"}, "Farmers_Walk": {"id": "Farmers_Walk", "name": "Farmer's Walk", "group": "Forearms", "muscle": "forearms", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Farmers_Walk/0.jpg", "/assets/exercises/Farmers_Walk/1.jpg"], "cues": ["Pick up a heavy dumbbell in each hand, standing tall between them.", "Brace your abs, pull your shoulders back and down, and look straight ahead.", "Walk with short controlled steps, not letting the weights swing.", "Walk until your grip is nearly gone, set them down under control, and rest."], "type": "timed", "home": "Carry two heavy shopping bags or water containers"}, "Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench": {"id": "Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench", "name": "Wrist Curl", "group": "Forearms", "muscle": "forearms", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg", "/assets/exercises/Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench/1.jpg"], "cues": ["Kneel beside a bench and rest your forearms on it, palms facing up, wrists just off the edge.", "Let the dumbbells roll down to your fingertips for a full stretch.", "Curl the weight back up by closing your hand and flexing your wrist as high as it goes.", "Lower slowly. Your forearms should never leave the bench."], "type": "weight", "home": "Wrist curls with a filled water bottle, forearm on your thigh"}, "Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench": {"id": "Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench", "name": "Reverse Wrist Curl", "group": "Forearms", "muscle": "forearms", "equipment": "dumbbell", "level": "beginner", "frames": ["/assets/exercises/Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg", "/assets/exercises/Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench/1.jpg"], "cues": ["Same setup as the wrist curl, but with your palms facing down and wrists off the bench edge.", "Let your hands drop toward the floor for a stretch across the top of the forearm.", "Lift the backs of your hands toward the ceiling, squeezing the top of the forearm.", "Go light. This one protects the wrist joint, it is not a strength contest."], "type": "weight", "home": "Reverse wrist curls with a light water bottle"}, "One-Arm_Kettlebell_Swings": {"id": "One-Arm_Kettlebell_Swings", "name": "Kettlebell Swing", "group": "Legs", "muscle": "hamstrings", "equipment": "kettlebells", "level": "intermediate", "frames": ["/assets/exercises/One-Arm_Kettlebell_Swings/0.jpg", "/assets/exercises/One-Arm_Kettlebell_Swings/1.jpg"], "cues": ["Hinge at the hips with a flat back, kettlebell swinging between your legs.", "Snap your hips forward to float the bell up to chest height, arm relaxed.", "Let it fall back, load the hips, and go again in a rhythm. Power comes from the hips, not the arm."], "type": "weight", "home": "Use a single dumbbell or a loaded backpack"}, "Goblet_Squat": {"id": "Goblet_Squat", "name": "Goblet Squat", "group": "Legs", "muscle": "quadriceps", "equipment": "kettlebells", "level": "beginner", "frames": ["/assets/exercises/Goblet_Squat/0.jpg", "/assets/exercises/Goblet_Squat/1.jpg"], "cues": ["Hold the kettlebell against your chest, elbows tucked.", "Sit down between your hips, chest tall, knees tracking over toes.", "Drive up through your heels. The bell up front keeps you upright."], "type": "weight", "home": "Use a single dumbbell or a loaded backpack"}, "Two-Arm_Kettlebell_Military_Press": {"id": "Two-Arm_Kettlebell_Military_Press", "name": "Kettlebell Press", "group": "Shoulders", "muscle": "shoulders", "equipment": "kettlebells", "level": "intermediate", "frames": ["/assets/exercises/Two-Arm_Kettlebell_Military_Press/0.jpg", "/assets/exercises/Two-Arm_Kettlebell_Military_Press/1.jpg"], "cues": ["Rack the bells at your shoulders, wrists straight.", "Brace your abs and press overhead without arching your back.", "Lower under control back to the rack."], "type": "weight", "home": "Use a single dumbbell or a loaded backpack"}, "One-Arm_Kettlebell_Row": {"id": "One-Arm_Kettlebell_Row", "name": "Kettlebell Row", "group": "Back", "muscle": "middle back", "equipment": "kettlebells", "level": "beginner", "frames": ["/assets/exercises/One-Arm_Kettlebell_Row/0.jpg", "/assets/exercises/One-Arm_Kettlebell_Row/1.jpg"], "cues": ["Hinge over with a flat back, one hand braced on your thigh or a bench.", "Row the bell to your hip, driving the elbow back, squeezing the shoulder blade.", "Lower to a full stretch. Do both sides."], "type": "weight", "home": "Use a single dumbbell or a loaded backpack"}, "Kettlebell_Hang_Clean": {"id": "Kettlebell_Hang_Clean", "name": "Kettlebell Clean", "group": "Legs", "muscle": "hamstrings", "equipment": "kettlebells", "level": "intermediate", "frames": ["/assets/exercises/Kettlebell_Hang_Clean/0.jpg", "/assets/exercises/Kettlebell_Hang_Clean/1.jpg"], "cues": ["Hinge and let the bell hang, then snap the hips to pull it up.", "Guide it around to the rack position at your shoulder, not slamming your wrist.", "Lower it back to the hang and repeat. It's a hip movement, not a curl."], "type": "weight", "home": "Use a single dumbbell or a loaded backpack"}};

