export const GROUPS = ['Chest','Back','Shoulders','Biceps','Triceps','Legs','Core','Forearms'];
const DOW = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];

export function newSlot(id) {
  const d = SLOT_DEFAULTS[id] || { sets: 3, reps: '10-12', rest: 75 };
  return { id, sets: d.sets, reps: d.reps, rest: d.rest };
}
export function dayForDate(plan, d = new Date()) {
  return plan.find(s => s.dow === DOW[d.getDay()]) || null;
}
export function estimateMinutes(day) {
  if (!day || !day.items) return 0;
  let sec = 5 * 60;
  for (const it of day.items) sec += (it.sets || 0) * (40 + (it.rest || 60));
  return Math.round(sec / 60);
}
export function libraryByGroup() {
  const out = {};
  for (const g of GROUPS) out[g] = [];
  for (const ex of Object.values(LIBRARY)) if (out[ex.group]) out[ex.group].push(ex);
  for (const g of GROUPS) out[g].sort((a, b) => a.name.localeCompare(b.name));
  return out;
}
